sql:
SELECT AVG(estimated_time) AS average_estimated_time
FROM tasks
WHERE assigned_user_id = 1;

SELECT COUNT(*) AS total_cards
FROM cards
WHERE project_id = 1;

SELECT COUNT(*) AS active_cards_count
FROM cards
WHERE project_id IN (SELECT project_id FROM projects WHERE status = 'Active');

external_knowledge:
- 'Treasures of productivity' refers to cards carrying significant tasks;
- 'Card creators and guardians' metaphorically represent the users who created and last updated the cards;
- 'Projects that hoard them' refers to the projects these cards belong to;
- 'Average estimated time to shine' is the average time needed to complete the tasks;
- 'Count of tasks within' denotes the total number of tasks associated with each card;
- 'From the most labor-intensive to the least' means ordering by the number of tasks in descending order.

sql:
SELECT COUNT(*) AS total_active_users
FROM users
WHERE status = 'Active';

SELECT title
FROM cards
WHERE priority = 'High';

external_knowledge:
- 'Sailors in the harbor' refers to 'users with pending tasks';
- 'Navigating their current voyages' refers to 'working on the tasks';
- 'Uncharted waters' refers to 'estimated time required for pending tasks'.

sql:
SELECT DISTINCT p.project_name, c.title
FROM projects p
JOIN cards c ON p.project_id = c.project_id;

external_knowledge:
- 'vibrant projects' refers to projects with an 'Active' status;
- 'bustling with activity' suggests projects that are not dormant and have ongoing tasks;
- 'high-priority items' means cards with a 'High' priority level.

sql:
SELECT AVG(priority) AS average_priority
FROM tasks
WHERE assigned_user_id = 1;
